### Fitting the Pseudo-Count Models


::: {.cell layout-align="center"}

```{.r .cell-code}
mod_sba <- cmdstan_model("stan/ch11b_sba.stan", dir = "simmodels")
mod_pba <- cmdstan_model("stan/ch11b_pba.stan", dir = "simmodels")
mod_wba <- cmdstan_model("stan/ch11b_wba.stan", dir = "simmodels")
```
:::



::: {.cell layout-align="center"}

```{.r .cell-code}
stan_data_base <- list(
  N          = nrow(df),
  y          = df$choice_red,
  k_self     = df$k_self,
  n_self     = df$n_self,
  k_social   = df$k_social,
  n_social   = df$n_social,
  run_diagnostics = 1L
)

if (regenerate_fits || !file.exists("simmodels/ch11b_sba_fit.rds")) {

  fit_sba <- mod_sba$sample(
    data = c(stan_data_base),
    chains = 4, parallel_chains = 4,
    iter_warmup = 1000, iter_sampling = 1000,
    refresh = 0
  )

  fit_pba <- mod_pba$sample(
    data = c(stan_data_base,
             list(prior_p_alpha = 2.0, prior_p_beta = 2.0)),
    chains = 4, parallel_chains = 4,
    iter_warmup = 1000, iter_sampling = 1000,
    refresh = 0
  )

  fit_wba <- mod_wba$sample(
    data = c(stan_data_base,
             list(prior_rho_alpha = 2.0, prior_rho_beta = 2.0,
                  prior_kappa_mu  = log(2), prior_kappa_sigma = 0.5)),
    chains = 4, parallel_chains = 4,
    iter_warmup = 1000, iter_sampling = 1000,
    refresh = 0
  )

  fit_sba$save_object("simmodels/ch11b_sba_fit.rds")
  fit_pba$save_object("simmodels/ch11b_pba_fit.rds")
  fit_wba$save_object("simmodels/ch11b_wba_fit.rds")

} else {
  fit_sba <- readRDS("simmodels/ch11b_sba_fit.rds")
  fit_pba <- readRDS("simmodels/ch11b_pba_fit.rds")
  fit_wba <- readRDS("simmodels/ch11b_wba_fit.rds")
}
```
:::


