## Validation: Simulation-Based Calibration Checks

Before fitting to empirical data we need confidence that our Stan samplers can recover parameters without bias. We run Simulation-Based Calibration Checks (SBC) on the three models with free parameters (WB, CI-Loops, CI-Full). The parameter-free SB model requires no SBC.

For each model we:
1. Draw parameters from the prior.
2. Simulate a dataset of 210 trials (6 repetitions of 35 evidence combinations) using those parameters and the actual experimental design.
3. Fit the model to that simulated dataset.
4. Check whether the true parameter lies within the expected rank-quantile band.


::: {.cell layout-align="center"}

```{.r .cell-code}
mod_sb_lo  <- cmdstan_model("stan/ch11b_sb_lo.stan",    dir = "simmodels")
mod_wb_lo  <- cmdstan_model("stan/ch11b_wb_lo.stan",    dir = "simmodels")
mod_ci_lo  <- cmdstan_model("stan/ch11b_ci_loops.stan", dir = "simmodels")
mod_cif_lo <- cmdstan_model("stan/ch11b_ci_full.stan",  dir = "simmodels")
```
:::



::: {.cell layout-align="center"}

```{.r .cell-code}
N_sbc_trials <- nrow(evidence_combinations) * 6L  # 210 trials

draw_w <- function() {
  w <- -1
  while (w < 0.5 || w > 1.0) w <- rnorm(1, 0.75, 0.25)
  w
}

make_sbc_data <- function(ev, lo_s, lo_o, L_post) {
  list(
    N        = nrow(ev),
    y        = rbinom(nrow(ev), 1, plogis(L_post)),
    k_self   = ev$k_self,   n_self   = ev$n_self,
    k_social = ev$k_social, n_social = ev$n_social,
    run_diagnostics = 0L
  )
}

sbc_gen_wb <- SBC_generator_function(
  function(N) {
    ws <- draw_w(); wo <- draw_w()
    ev <- evidence_combinations |> slice_sample(n = N, replace = TRUE)
    lo_s <- log((0.5 + ev$k_self)   / (0.5 + ev$n_self   - ev$k_self))
    lo_o <- log((0.5 + ev$k_social) / (0.5 + ev$n_social - ev$k_social))
    L    <- jardri_f(lo_s, ws) + jardri_f(lo_o, wo)
    list(
      variables = list(w_self = ws, w_social = wo),
      generated = make_sbc_data(ev, lo_s, lo_o, L)
    )
  }, N = N_sbc_trials
)

sbc_gen_ci <- SBC_generator_function(
  function(N) {
    ws <- draw_w(); wo <- draw_w()
    as_m1 <- abs(rnorm(1, 0, 1)); ao_m1 <- abs(rnorm(1, 0, 1))
    as <- 1 + as_m1; ao <- 1 + ao_m1
    ev <- evidence_combinations |> slice_sample(n = N, replace = TRUE)
    lo_s <- log((0.5 + ev$k_self)   / (0.5 + ev$n_self   - ev$k_self))
    lo_o <- log((0.5 + ev$k_social) / (0.5 + ev$n_social - ev$k_social))
    L    <- jardri_f(as * lo_s, ws) + jardri_f(ao * lo_o, wo)
    list(
      variables = list(w_self = ws, w_social = wo,
                       alpha_self_m1 = as_m1, alpha_social_m1 = ao_m1),
      generated = make_sbc_data(ev, lo_s, lo_o, L)
    )
  }, N = N_sbc_trials
)

sbc_gen_cif <- SBC_generator_function(
  function(N) {
    ws <- draw_w(); wo <- draw_w()
    as_m1 <- abs(rnorm(1, 0, 1)); ao_m1 <- abs(rnorm(1, 0, 1))
    as <- 1 + as_m1; ao <- 1 + ao_m1
    ev <- evidence_combinations |> slice_sample(n = N, replace = TRUE)
    lo_s <- log((0.5 + ev$k_self)   / (0.5 + ev$n_self   - ev$k_self))
    lo_o <- log((0.5 + ev$k_social) / (0.5 + ev$n_social - ev$k_social))
    I    <- jardri_f(as * lo_s, ws) + jardri_f(ao * lo_o, wo)
    L    <- jardri_f(lo_s + I, ws) + jardri_f(lo_o + I, wo)
    list(
      variables = list(w_self = ws, w_social = wo,
                       alpha_self_m1 = as_m1, alpha_social_m1 = ao_m1),
      generated = make_sbc_data(ev, lo_s, lo_o, L)
    )
  }, N = N_sbc_trials
)
```
