  n_sbc <- 300
  sampler_args <- list(
    chains = 2, iter_warmup = 500, iter_sampling = 500,
    parallel_chains = 2, refresh = 0
  )

  ds_wb  <- generate_datasets(sbc_gen_wb,  n_sbc)
