for (nm in c("SB", "WB", "CI-Loops", "CI-Full")) {
  fit <- list(SB = fit_sb_lo, WB = fit_wb_lo,
              `CI-Loops` = fit_ci_lo, `CI-Full` = fit_cif_lo)[[nm]]
  dg  <- fit$diagnostic_summary(quiet = TRUE)
  cat(nm, "— divergences:", sum(dg$num_divergent),
      " max Rhat:", round(max(fit$summary()$rhat, na.rm = TRUE), 3), "\n")
}
