## Group Differences: Controls vs Schizophrenia

### Separate Fits by Group

We now fit the winning model separately to each group. This allows direct comparison of the weight and loop parameters between healthy controls and patients with schizophrenia.


::: {.cell layout-align="center"}

```{.r .cell-code}
make_stan_data_lo <- function(grp) {
  d <- df |> filter(group_label == grp)
  list(
    N        = nrow(d),
    y        = d$choice_red,
    k_self   = d$k_self,   n_self   = d$n_self,
    k_social = d$k_social, n_social = d$n_social,
    run_diagnostics = 1L
  )
}

if (regenerate_fits || !file.exists("simmodels/ch11b_ctrl_fit.rds")) {

  fit_ctrl <- mod_ci_lo$sample(
    data = make_stan_data_lo("Control"),
    chains = 4, parallel_chains = 4,
    iter_warmup = 1000, iter_sampling = 1000, refresh = 0
  )

  fit_scz <- mod_ci_lo$sample(
    data = make_stan_data_lo("Schizophrenia"),
    chains = 4, parallel_chains = 4,
    iter_warmup = 1000, iter_sampling = 1000, refresh = 0
  )

  fit_ctrl$save_object("simmodels/ch11b_ctrl_fit.rds")
  fit_scz$save_object("simmodels/ch11b_scz_fit.rds")

} else {
  fit_ctrl <- readRDS("simmodels/ch11b_ctrl_fit.rds")
  fit_scz  <- readRDS("simmodels/ch11b_scz_fit.rds")
}
